useSse(client, url, events, onEvent) {
const onEventRef = useRef(onEvent)
useEffect(() => {
onEventRef.current = onEvent
}, [onEvent])
useEffect(() => {
if (url == null) return
const connection = client.connect(
url,
events,
(name, data) => onEventRef.current(name, data),
setStatus,
)
return () => connection.close()
}, [client, url, events])
}

useWs(client, url, events, onEvent) {
const onEventRef = useRef(onEvent)
const connectionRef = useRef(null)
useEffect(() => { onEventRef.current = onEvent }, [onEvent])
useEffect(() => {
if (url == null) return
const connection = client.connect(
url, events,
(name, data) => onEventRef.current(name, data),
setStatus,
)
connectionRef.current = connection
return () => { connection.close(); connectionRef.current = null }
}, [client, url, events])
const send = useCallback((name, data) => {
connectionRef.current?.send(name, data)
}, [])
return { send }
}
